// Generate sample emissions data for carbon accounting
const facilities = [
  { name: 'Manufacturing Plant A', location: 'California, USA', type: 'Production' },
  { name: 'Distribution Center B', location: 'Texas, USA', type: 'Logistics' },
  { name: 'Office Complex C', location: 'New York, USA', type: 'Administrative' },
  { name: 'Research Lab D', location: 'Massachusetts, USA', type: 'R&D' },
  { name: 'Warehouse E', location: 'Illinois, USA', type: 'Storage' }
];

const emissionsData = [];

for (let i = 0; i < facilities.length; i++) {
  const facility = facilities[i];

  // Generate random energy consumption (kWh)
  const electricityConsumption = Math.floor(Math.random() * 500000) + 100000;
  const naturalGasConsumption = Math.floor(Math.random() * 300000) + 50000;

  // Generate random emissions values (metric tons CO2e)
  const scope1Emissions = Math.floor(Math.random() * 1000) + 200; // Direct emissions
  const scope2Emissions = Math.floor(Math.random() * 800) + 150; // Indirect emissions from purchased energy
  const scope3Emissions = Math.floor(Math.random() * 1500) + 300; // Other indirect emissions

  const totalEmissions = scope1Emissions + scope2Emissions + scope3Emissions;

  emissionsData.push({
    facilityId: `FAC-${String(i + 1).padStart(3, '0')}`,
    facilityName: facility.name,
    location: facility.location,
    facilityType: facility.type,
    reportingPeriod: '2024-Q1',
    energyConsumption: {
      electricity: electricityConsumption,
      naturalGas: naturalGasConsumption,
      unit: 'kWh'
    },
    emissions: {
      scope1: scope1Emissions,
      scope2: scope2Emissions,
      scope3: scope3Emissions,
      total: totalEmissions,
      unit: 'metric tons CO2e'
    },
    emissionsIntensity: parseFloat((totalEmissions / (electricityConsumption + naturalGasConsumption) * 1000).toFixed(4)),
    dataQuality: Math.random() > 0.3 ? 'High' : 'Medium',
    verificationStatus: 'Pending',
    timestamp: new Date().toISOString()
  });
}

return emissionsData.map(data => ({ json: data }));
